	private record WinnerDependencyRevision(long clearRevision, long winnerRevision) {

		private static WinnerDependencyRevision capture(Memo memo, WinnerKey key) {
			return new WinnerDependencyRevision(memo.winnerClearRevision(key.groupId()), memo.winnerRevision(key));
		}

		private boolean current(Memo memo, WinnerKey key) {
			return clearRevision == memo.winnerClearRevision(key.groupId())
					&& winnerRevision == memo.winnerRevision(key);
		}
	}

	private record GroupSearchStamp(GroupSearchRevision groupRevision,
			Map<WinnerKey, WinnerDependencyRevision> childWinnerRevisions) {

		private GroupSearchStamp {
			Objects.requireNonNull(groupRevision, "groupRevision");
			childWinnerRevisions = childWinnerRevisions == null || childWinnerRevisions.isEmpty()
					? Map.of()
					: Map.copyOf(childWinnerRevisions);
		}

		private boolean current(Memo memo, GroupSearchRevision currentGroupRevision) {
			return groupRevision.equals(currentGroupRevision)
					&& childWinnerRevisions.entrySet()
							.stream()
							.allMatch(entry -> entry.getValue().current(memo, entry.getKey()));
		}
	}

	private record ExpressionWork(PendingOptimizationTask.Kind kind, int groupId, int expressionId,
			RuleDependencyRevision revision, Set<RuleWakeUpEvent> wakeUpEvents,
			Set<RuleDescriptor.MemoFact> changedFacts, String wakeUpReason) {

		private ExpressionWork {
			wakeUpEvents = immutableWakeUpEvents(wakeUpEvents);
			changedFacts = immutableMemoFacts(changedFacts);
		}

		PendingOptimizationTask pendingTask() {
			return new PendingOptimizationTask(kind, groupId, expressionId, "", wakeUpReason);
		}

		ExpressionWork merge(ExpressionWork later) {
			if (later == null) {
				return this;
			}
			if (kind != later.kind || groupId != later.groupId || expressionId != later.expressionId) {
				throw new IllegalArgumentException("Cannot merge work for different memo expressions");
			}
			EnumSet<RuleWakeUpEvent> events = EnumSet.noneOf(RuleWakeUpEvent.class);
			events.addAll(wakeUpEvents);
			events.addAll(later.wakeUpEvents);
			EnumSet<RuleDescriptor.MemoFact> facts = EnumSet.noneOf(RuleDescriptor.MemoFact.class);
			facts.addAll(changedFacts);
			facts.addAll(later.changedFacts);
			String reason = wakeUpReason.equals(later.wakeUpReason)
					? wakeUpReason
					: "coalesced:" + events.stream().map(Enum::name).sorted().toList();
			return new ExpressionWork(kind, groupId, expressionId, revision.merge(later.revision), events, facts,
					reason);
		}
	}

	private record ExpressionWorkKey(PendingOptimizationTask.Kind kind, int expressionId) {
	}

	private record RulePassKey(PendingOptimizationTask.Kind kind, int expressionId, WinnerKey goalKey) {
	}

	private static Set<RuleWakeUpEvent> immutableWakeUpEvents(Set<RuleWakeUpEvent> wakeUpEvents) {
		if (wakeUpEvents == null || wakeUpEvents.isEmpty()) {
			return Set.of();
		}
		return Collections.unmodifiableSet(EnumSet.copyOf(wakeUpEvents));
	}

	private static Set<RuleDescriptor.MemoFact> immutableMemoFacts(Set<RuleDescriptor.MemoFact> facts) {
		if (facts == null || facts.isEmpty()) {
			return Set.of();
		}
		return Collections.unmodifiableSet(EnumSet.copyOf(facts));
	}

	private static final class MemoChangeBatch {
		private final Map<Integer, EnumSet<RuleWakeUpEvent>> expressionEvents = new LinkedHashMap<>();
		private final EnumSet<RuleWakeUpEvent> groupEvents = EnumSet.noneOf(RuleWakeUpEvent.class);
		private final EnumSet<RuleDescriptor.MemoFact> changedFacts = EnumSet.noneOf(
				RuleDescriptor.MemoFact.class);
		private final Set<MemoChange.Kind> kinds = new LinkedHashSet<>();

		private void add(MemoChange change) {
			kinds.add(change.kind());
			switch (change.kind()) {
			case LOGICAL_EXPRESSION_ADDED -> addExpressionEvent(change.expressionId(),
					RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED);
			case PHYSICAL_EXPRESSION_ADDED -> {
				addExpressionEvent(change.expressionId(), RuleWakeUpEvent.PHYSICAL_EXPRESSION_ADDED);
				groupEvents.add(RuleWakeUpEvent.PHYSICAL_FRONTIER_CHANGED);
			}
			case PROOFS_CHANGED -> addExpressionEvent(change.expressionId(), RuleWakeUpEvent.PROOF_CHANGED);
			case ADMISSIBILITY_CHANGED -> addExpressionEvent(change.expressionId(),
					RuleWakeUpEvent.REQUIRED_PROPERTIES_CHANGED);
			case FACTS_CHANGED -> {
				changedFacts.addAll(change.changedFacts());
				groupEvents.add(RuleWakeUpEvent.LOGICAL_FACT_CHANGED);
				if (change.changedFacts().isEmpty()
						|| change.changedFacts().contains(RuleDescriptor.MemoFact.COST_ESTIMATE)) {
					groupEvents.add(RuleWakeUpEvent.ESTIMATE_CHANGED);
				}
			}
			case DEPENDENCY_CHANGED -> addExpressionEvent(change.expressionId(),
					RuleWakeUpEvent.CHILD_EXPRESSION_CHANGED);
			case CHILD_PHYSICAL_FRONTIER_CHANGED -> addExpressionEvent(change.expressionId(),
					RuleWakeUpEvent.CHILD_PHYSICAL_FRONTIER_CHANGED);
			case CHILD_WINNER_CHANGED -> addExpressionEvent(change.expressionId(),
					RuleWakeUpEvent.CHILD_WINNER_CHANGED);
			case WINNER_FRONTIER_CHANGED -> {
				// The changed winner is this group's output. Reverse-dependency changes wake its parents above.
			}
			}
		}

		private void addExpressionEvent(int expressionId, RuleWakeUpEvent event) {
			if (expressionId < 0) {
				groupEvents.add(event);
				return;
			}
			expressionEvents.computeIfAbsent(expressionId, ignored -> EnumSet.noneOf(RuleWakeUpEvent.class))
					.add(event);
		}

		private boolean requiresWholeGroup() {
			return !groupEvents.isEmpty();
		}

		private Set<Integer> expressionIds() {
			return expressionEvents.keySet();
		}

		private Set<RuleDescriptor.MemoFact> changedFacts() {
			return changedFacts.isEmpty() ? Set.of() : Collections.unmodifiableSet(EnumSet.copyOf(changedFacts));
		}

		private Set<RuleWakeUpEvent> eventsFor(int expressionId) {
			EnumSet<RuleWakeUpEvent> events = groupEvents.isEmpty()
					? EnumSet.noneOf(RuleWakeUpEvent.class)
					: EnumSet.copyOf(groupEvents);
			Set<RuleWakeUpEvent> expressionSpecific = expressionEvents.get(expressionId);
			if (expressionSpecific != null) {
				events.addAll(expressionSpecific);
			}
			return events.isEmpty() ? Set.of() : Collections.unmodifiableSet(events);
		}

		private boolean wakesJoinSearch(int expressionId) {
			return eventsFor(expressionId).stream().anyMatch(event -> event != RuleWakeUpEvent.PHYSICAL_EXPRESSION_ADDED
					&& event != RuleWakeUpEvent.PHYSICAL_FRONTIER_CHANGED
					&& event != RuleWakeUpEvent.CHILD_PHYSICAL_FRONTIER_CHANGED
					&& event != RuleWakeUpEvent.CHILD_WINNER_CHANGED);
		}

		private boolean wakesJoinSubscriptions() {
			if (kinds.contains(MemoChange.Kind.LOGICAL_EXPRESSION_ADDED)
					|| kinds.contains(MemoChange.Kind.PROOFS_CHANGED)
					|| kinds.contains(MemoChange.Kind.ADMISSIBILITY_CHANGED)) {
				return true;
			}
			return kinds.contains(MemoChange.Kind.FACTS_CHANGED)
					&& changedFacts.stream().anyMatch(fact -> fact != RuleDescriptor.MemoFact.COST_ESTIMATE);
		}

		private boolean wakesDependentWork() {
			return kinds.stream().anyMatch(kind -> kind != MemoChange.Kind.PHYSICAL_EXPRESSION_ADDED
					&& kind != MemoChange.Kind.CHILD_PHYSICAL_FRONTIER_CHANGED);
		}

		private String wakeUpReason() {
			return kinds.stream()
					.map(kind -> kind.name().toLowerCase(java.util.Locale.ROOT))
					.sorted()
					.collect(java.util.stream.Collectors.joining(","));
		}
	}

